<?php require_once 'db.php'; $u=require_login('student'); $st=pdo()->prepare('SELECT b.*,t.table_code,p.transaction_id FROM bookings b JOIN library_tables t ON t.id=b.table_id LEFT JOIN payments p ON p.booking_id=b.id WHERE b.student_id=? ORDER BY b.created_at DESC'); $st->execute([$u['id']]); app_header('Booking Status'); ?><section class="card"><h1>Booking Status</h1><table><tr><th>Table</th><th>Status</th><th>Reason</th><th>Transaction</th></tr><?php foreach($st as $b):?><tr><td><?=e($b['table_code'])?></td><td><span class="status <?=e($b['status'])?>"><?=e($b['status'])?></span></td><td><?=e($b['rejection_reason'])?></td><td><?=e($b['transaction_id'])?></td></tr><?php endforeach;?></table></section><?php app_footer(); ?>
